package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVFormatParseTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testParseWithValidReader() throws IOException {
        Reader reader = mock(Reader.class);
        CSVParser parser = csvFormat.parse(reader);
        assertNotNull(parser);
        // The CSVParser constructor should have been called with the given reader and this CSVFormat
        // Since CSVParser is not mocked here, just check the type and non-nullity
        assertSame(reader, parser.getReader());
        assertSame(csvFormat, parser.getFormat());
    }

    @Test
    void testParseThrowsIOException() {
        Reader reader = mock(Reader.class);
        try {
            // We cannot simulate IOException from CSVFormat.parse directly since it just calls new CSVParser(in, this).
            // So just verify that parse method declares IOException.
            csvFormat.parse(reader);
        } catch (IOException e) {
            fail("IOException should not be thrown by parse with mocked reader");
        }
    }
}
